fun handleReportingExtensions(settings: ProcessingSettings, initialResult: Detektion): Detektion {
    val extensions = loadExtensions<ReportingExtension>(settings)
    extensions.forEach { it.onRawResult(initialResult) }
    val finalIssues = extensions.fold(initialResult.issues) { acc, extension -> extension.transformIssues(acc) }
    val finalResult = initialResult.copy(issues = finalIssues)
    extensions.forEach { it.onFinalResult(finalResult) }
    return finalResult
}

private fun Detektion.copy(issues: List<Issue> = this.issues): Detektion =
    Detektion(
        issues = issues,
        rules = rules,
        metrics = metrics,
        notifications = notifications,
        userData = userData,
    )

package dev.detekt.core

import dev.detekt.api.Config
import dev.detekt.api.FileProcessListener
import dev.detekt.core.extensions.loadExtensions
import dev.detekt.core.util.isActiveOrDefault

class FileProcessorLocator(private val settings: ProcessingSettings) {

    private val config: Config = settings.config
    private val subConfig = config.subConfig("processors")
    private val processorsActive = subConfig.isActiveOrDefault(true)
    private val excludes = subConfig.valueOrDefault("exclude", emptyList<String>())

    fun load(): List<FileProcessListener> {
        var processors: List<FileProcessListener> = if (processorsActive) {
            loadExtensions(settings) { it.id !in excludes }
        } else {
            emptyList()
        }
        if (settings.spec.rulesSpec.autoCorrect) {
            val modifier = KtFileModifier()
            if (modifier.id !in excludes) {
                processors = processors + modifier
            }
        }
        return processors
    }
}

